}

$gitCommand = Get-PrerequisiteCommand -Name "git" -Config $config -Runtime $runtime -Profile $profile
$pythonCommand = Get-PrerequisiteCommand -Name "python" -Config $config -Runtime $runtime -Profile $profile

$resolvedUpstreamUrl = if (-not [string]::IsNullOrWhiteSpace($UpstreamUrl)) {
