$targetRepositoryParent = Split-Path -Path $profile.TargetRepositoryPath -Parent
$venvPath = Resolve-ExperimentPath -Path $runtime.venvPath
$venvPython = Join-Path $venvPath "Scripts/python.exe"
$pipCachePath = Join-Path $localRoot "pip-cache"

foreach ($directory in @($localRoot, $checkoutParent, $logsRoot, $workspacePath, $targetRepositoryParent, $pipCachePath)) {
    New-Item -ItemType Directory -Force -Path $directory | Out-Null
}

$checkoutGitDirectory = Join-Path $checkoutPath ".git"
if (-not (Test-Path -LiteralPath $checkoutPath)) {
    Invoke-GitCommand -GitCommand $gitCommand -Arguments @("clone", "-c", "core.longpaths=true", "--branch", $resolvedBranch, "--single-branch", $resolvedUpstreamUrl, $checkoutPath) -Description "Clone upstream repository"
}
else {
    if (-not (Test-Path -LiteralPath $checkoutGitDirectory)) {
        Write-Warning "Existing upstream checkout is not a git repository. Recreating it."
        Reset-Directory -Path $checkoutPath
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("clone", "-c", "core.longpaths=true", "--branch", $resolvedBranch, "--single-branch", $resolvedUpstreamUrl, $checkoutPath) -Description "Clone upstream repository"
    }
    else {
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "config", "core.longpaths", "true") -Description "Persist long-path support in upstream checkout"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "remote", "set-url", "origin", $resolvedUpstreamUrl) -Description "Update upstream origin"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "fetch", "--prune", "origin") -Description "Fetch upstream repository"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "reset", "--hard", "HEAD") -Description "Discard local tracked changes before branch alignment"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "clean", "-fdx") -Description "Remove untracked upstream files before branch alignment"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "checkout", "-B", $resolvedBranch, "origin/$resolvedBranch") -Description "Align local branch with upstream"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "reset", "--hard", "origin/$resolvedBranch") -Description "Reset checkout to upstream state"
        Invoke-GitCommand -GitCommand $gitCommand -Arguments @("-C", $checkoutPath, "clean", "-fdx") -Description "Remove untracked upstream files"
    }
}

$basePythonVersion = Get-PythonVersion -Command $pythonCommand
$recreateVenv = -not (Test-Path -LiteralPath $venvPython)
if (-not $recreateVenv) {
    try {
        $venvPythonVersion = Get-PythonVersion -Command $venvPython
        if ($venvPythonVersion.Major -ne $basePythonVersion.Major -or $venvPythonVersion.Minor -ne $basePythonVersion.Minor) {
            $recreateVenv = $true
        }
    }
    catch {
        $recreateVenv = $true
    }
}

if ($recreateVenv) {
    Write-Host "Recreating repo-local virtual environment."
    Reset-Directory -Path $venvPath
    Invoke-ExternalCommand -Command $pythonCommand -Arguments @("-m", "venv", $venvPath) -Description "Create repo-local virtual environment"
}
else {
    Write-Host "Reusing existing repo-local virtual environment."
}

$env:PIP_CACHE_DIR = $pipCachePath
Invoke-ExternalCommand -Command $venvPython -Arguments @("-m", "pip", "install", "--editable", $checkoutPath) -Description "Install upstream package in editable mode"

Write-Host ("Bootstrap complete for profile '{0}'. Upstream checkout: {1}" -f $profile.Id, $checkoutPath)
Write-Host ("Bootstrap complete for profile '{0}'. Virtual environment: {1}" -f $profile.Id, $venvPath)
